{% load static %}
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ollama Chat</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <script src="https://unpkg.com/htmx.org@1.9.12"></script>
    <script src="https://unpkg.com/htmx.org/extensions/ws.js"></script>
    <style>
        .chat-container { height: calc(100vh - 160px); }
        .message-bubble { max-width: 80%; word-wrap: break-word; }
    </style>
</head>
<body class="bg-gray-100 h-screen flex flex-col">
    <header class="bg-white shadow-sm p-4 flex justify-between items-center">
        <h1 class="text-xl font-bold text-gray-800">Ollama Chat</h1>
        <div class="text-sm text-gray-500" id="status">Connecting...</div>
    </header>

    <main id="chat-window" class="chat-container overflow-y-auto p-4 space-y-4 flex-grow">
        <!-- Messages will appear here -->
    </main>

    <footer class="p-4 bg-white border-t">
        <div class="max-w-4xl mx-auto flex gap-2">
            <input type="text" id="user-input" 
                   class="flex-grow p-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500" 
                   placeholder="Type a message..."
                   onkeypress="if(event.key === 'Enter') sendMessage()">
            <button onclick="sendMessage()" 
                    class="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors">
                Send
            </button>
        </div>
    </footer>

    <script>
        const chatWindow = document.getElementById('chat-window');
        const statusDiv = document.getElementById('status');
        const userInput = document.getElementById('user-input');

        const protocol = window.location.protocol === 'https:' ? 'wss' : 'ws';
        const ws = new WebSocket(`${protocol}://${window.location.host}/ws/chat/`);

        ws.onopen = () => {
            statusDiv.innerText = 'Connected';
            statusDiv.className = 'text-sm text-green-500';
        };

        ws.onclose = () => {
            statusDiv.innerText = 'Disconnected';
            statusDiv.className = 'text-sm text-red-500';
        };

        ws.onmessage = (event) => {
            const data = JSON.parse(event.data);

            if (data.type === 'user_message') {
                appendMessage('user', data.text);
            } else if (data.type === 'bot_token') {
                appendToken('bot', data.text);
            } else if (data.type === 'bot_end') {
                finalizeBotMessage();
            } else if (data.type === 'error') {
                appendMessage('error', 'Error: ' + data.text);
            }
        };

        let currentBotMessageDiv = null;

        function appendMessage(role, text) {
            const div = document.createElement('div');
            div.className = `flex ${role === 'user' ? 'justify-end' : 'justify-start'}`;

            const bubble = document.createElement('div');
            bubble.className = `message-bubble p-3 rounded-lg ${
                role === 'user' 
                ? 'bg-blue-600 text-white rounded-br-none' 
                : role === 'error' 
                ? 'bg-red-100 text-red-700 rounded-br-none' 
                : 'bg-white text-gray-800 shadow-sm rounded-bl-none border'
            }`;
            bubble.innerText = text;

            div.appendChild(bubble);
            chatWindow.appendChild(div);
            chatWindow.scrollTop = chatWindow.scrollHeight;
            return div;
        }

        function appendToken(role, token) {
            if (!currentBotMessageDiv) {
                const div = appendMessage('bot', '');
                currentBotMessageDiv = div.querySelector('.message-bubble');
            }
            currentBotMessageDiv.innerText += token;
            chatWindow.scrollTop = chatWindow.scrollHeight;
        }

        function finalizeBotMessage() {
            currentBotMessageDiv = null;
        }

        function sendMessage() {
            const text = userInput.value.trim();
            if (!text) return;

            ws.send(JSON.stringify({ message: text }));
            userInput.value = '';
        }
    </script>
</body>
</html>

